import { useEffect, useRef, useState, useCallback } from 'react';

/* ─── Pain point data ─── */
const PAIN_POINTS = [
  { id: 'shoulder', label: 'Shoulder', cx: 310, cy: 148, desc: 'Rotator Cuff' },
  { id: 'back',     label: 'Lower Back', cx: 230, cy: 310, desc: 'Lumbar Region' },
  { id: 'knee',     label: 'Knee Joint', cx: 265, cy: 490, desc: 'Inflammation' },
  { id: 'neck',     label: 'Neck',       cx: 230, cy: 90,  desc: 'Cervical Spine' },
];

/* ─── Interactive Medical Body ─── */
const MedicalBody = () => {
  const containerRef = useRef(null);
  const [mouse, setMouse] = useState({ x: 0, y: 0 });
  const [hovered, setHovered] = useState(null);
  const [scanY, setScanY] = useState(-20);
  const rafRef = useRef(null);
  const scanRef = useRef(-20);
  const scanDir = useRef(1);

  // Mouse tracking
  const handleMouseMove = useCallback((e) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width - 0.5) * 2;
    const y = ((e.clientY - rect.top) / rect.height - 0.5) * 2;
    setMouse({ x, y });
  }, []);

  // Animate scan line
  useEffect(() => {
    const tick = () => {
      scanRef.current += scanDir.current * 1.8;
      if (scanRef.current > 600) scanDir.current = -1;
      if (scanRef.current < -20) scanDir.current = 1;
      setScanY(scanRef.current);
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, []);

  const rotateX = mouse.y * -6;
  const rotateY = mouse.x * 8;
  const tiltX = mouse.x * 12;
  const tiltY = mouse.y * 8;

  return (
    <div
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={() => { setMouse({ x: 0, y: 0 }); setHovered(null); }}
      style={{
        position: 'relative',
        width: '420px',
        height: '580px',
        cursor: 'crosshair',
        perspective: '900px',
      }}
    >
      {/* Outer ambient glow */}
      <div style={{
        position: 'absolute', inset: 0,
        background: 'radial-gradient(ellipse at 50% 50%, rgba(219,38,29,0.10) 0%, transparent 70%)',
        borderRadius: '50%',
        transition: 'opacity 0.4s',
        pointerEvents: 'none',
      }} />

      {/* Body SVG */}
      <div style={{
        transform: `rotateX(${rotateX}deg) rotateY(${rotateY}deg) translate(${tiltX}px, ${tiltY}px)`,
        transition: 'transform 0.12s ease-out',
        transformStyle: 'preserve-3d',
        willChange: 'transform',
      }}>
        <svg
          viewBox="0 0 460 620"
          width="420"
          height="580"
          xmlns="http://www.w3.org/2000/svg"
          style={{
            filter: 'drop-shadow(0 0 18px rgba(219,38,29,0.45)) drop-shadow(0 0 40px rgba(150,0,0,0.2))',
            display: 'block',
          }}
        >
          <defs>
            {/* Main body gradient — deep red/dark theme */}
            <linearGradient id="bodyG" x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%"   stopColor="#1a0000" stopOpacity="0.95"/>
              <stop offset="35%"  stopColor="#3d0a0a" stopOpacity="1"/>
              <stop offset="65%"  stopColor="#5a1010" stopOpacity="1"/>
              <stop offset="100%" stopColor="#2a0606" stopOpacity="0.95"/>
            </linearGradient>
            <linearGradient id="bodyGV" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%"   stopColor="#5c1212"/>
              <stop offset="40%"  stopColor="#3d0808"/>
              <stop offset="100%" stopColor="#1e0404"/>
            </linearGradient>
            <radialGradient id="bodyShine" cx="38%" cy="22%" r="55%">
              <stop offset="0%"   stopColor="rgba(255,120,100,0.18)"/>
              <stop offset="100%" stopColor="rgba(80,0,0,0)"/>
            </radialGradient>
            <radialGradient id="boneG" cx="50%" cy="50%" r="50%">
              <stop offset="0%"   stopColor="rgba(255,180,160,0.25)"/>
              <stop offset="100%" stopColor="rgba(219,38,29,0)"/>
            </radialGradient>
            <radialGradient id="painG" cx="50%" cy="50%" r="50%">
              <stop offset="0%"   stopColor="#ffffff" stopOpacity="1"/>
              <stop offset="20%"  stopColor="#ffcc44" stopOpacity="0.95"/>
              <stop offset="55%"  stopColor="#ff4400" stopOpacity="0.85"/>
              <stop offset="100%" stopColor="#cc0000" stopOpacity="0"/>
            </radialGradient>
            <linearGradient id="scanG" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%"   stopColor="rgba(219,38,29,0)"/>
              <stop offset="50%"  stopColor="rgba(255,80,60,0.7)"/>
              <stop offset="100%" stopColor="rgba(219,38,29,0)"/>
            </linearGradient>
            <filter id="gB" x="-30%" y="-30%" width="160%" height="160%">
              <feGaussianBlur stdDeviation="2.5" result="b"/>
              <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
            </filter>
            <filter id="gS" x="-60%" y="-60%" width="220%" height="220%">
              <feGaussianBlur stdDeviation="5" result="b"/>
              <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
            </filter>
            <clipPath id="bodyClip">
              <rect x="0" y="0" width="460" height="620"/>
            </clipPath>
          </defs>

          {/* ══ HEAD ══ */}
          {/* Skull shape */}
          <ellipse cx="230" cy="60" rx="46" ry="52"
            fill="url(#bodyG)" stroke="#db261d" strokeWidth="1.4" filter="url(#gB)"/>
          <ellipse cx="230" cy="60" rx="46" ry="52" fill="url(#bodyShine)"/>
          {/* Jaw */}
          <path d="M190 82 Q191 108 210 115 Q230 120 250 115 Q269 108 270 82"
            fill="url(#bodyG)" stroke="#db261d" strokeWidth="1.2"/>
          {/* Facial features hint */}
          <ellipse cx="218" cy="56" rx="7" ry="5" fill="rgba(219,38,29,0.2)" stroke="rgba(219,38,29,0.4)" strokeWidth="0.8"/>
          <ellipse cx="242" cy="56" rx="7" ry="5" fill="rgba(219,38,29,0.2)" stroke="rgba(219,38,29,0.4)" strokeWidth="0.8"/>
          {/* Nose hint */}
          <path d="M228 62 Q230 70 232 62" stroke="rgba(219,38,29,0.3)" strokeWidth="1" fill="none"/>
          {/* Ears */}
          <ellipse cx="183" cy="63" rx="6" ry="10" fill="url(#bodyGV)" stroke="#db261d" strokeWidth="1"/>
          <ellipse cx="277" cy="63" rx="6" ry="10" fill="url(#bodyGV)" stroke="#db261d" strokeWidth="1"/>
          {/* Neck */}
          <path d="M208 110 L208 138 Q230 145 252 138 L252 110 Q230 118 208 110Z"
            fill="url(#bodyGV)" stroke="#db261d" strokeWidth="1.1"/>

          {/* ══ NECK BONES / CERVICAL ══ */}
          {[120,127,134].map((y, i) => (
            <ellipse key={i} cx="230" cy={y} rx="10" ry="4"
              fill="rgba(219,38,29,0.15)" stroke="rgba(219,38,29,0.35)" strokeWidth="0.7"/>
          ))}

          {/* ══ SHOULDERS ══ */}
          <ellipse cx="155" cy="155" rx="30" ry="22" fill="url(#bodyG)" stroke="#db261d" strokeWidth="1.2" filter="url(#gB)"/>
          <ellipse cx="305" cy="155" rx="30" ry="22" fill="url(#bodyG)" stroke="#db261d" strokeWidth="1.2" filter="url(#gB)"/>
          {/* Shoulder shine */}
          <ellipse cx="150" cy="148" rx="12" ry="8" fill="rgba(255,100,80,0.12)"/>
          <ellipse cx="300" cy="148" rx="12" ry="8" fill="rgba(255,100,80,0.12)"/>

          {/* ══ CLAVICLE / COLLAR BONES ══ */}
          <path d="M208 138 Q190 145 160 152" stroke="rgba(219,38,29,0.55)" strokeWidth="2" fill="none" strokeLinecap="round"/>
          <path d="M252 138 Q270 145 300 152" stroke="rgba(219,38,29,0.55)" strokeWidth="2" fill="none" strokeLinecap="round"/>

          {/* ══ CHEST / TORSO ══ */}
          <path d="
            M160 152 C148 158 140 172 138 190 L136 240
            C135 250 140 256 148 254
            L150 310 L152 360
            C152 368 148 374 144 380 L138 430
            C137 442 143 452 155 452 L160 452
            C168 452 174 447 175 439 L183 390 L188 372
            L230 368 L272 372 L277 390 L285 439
            C286 447 292 452 300 452 L305 452
            C317 452 323 442 322 430 L316 380
            C312 374 308 368 308 360 L310 310 L312 254
            C320 256 325 250 324 240 L322 190
            C320 172 312 158 300 152 Z
          " fill="url(#bodyG)" stroke="#db261d" strokeWidth="1.4" filter="url(#gB)"/>
          {/* Chest shine */}
          <path d="
            M160 152 C148 158 140 172 138 190 L136 240
            C135 250 140 256 148 254
            L150 310 L152 360
            C152 368 148 374 144 380 L138 430
            C137 442 143 452 155 452 L160 452
            C168 452 174 447 175 439 L183 390 L188 372
            L230 368 L272 372 L277 390 L285 439
            C286 447 292 452 300 452 L305 452
            C317 452 323 442 322 430 L316 380
            C312 374 308 368 308 360 L310 310 L312 254
            C320 256 325 250 324 240 L322 190
            C320 172 312 158 300 152 Z
          " fill="url(#bodyShine)"/>

          {/* ══ RIB CAGE ══ */}
          {/* Sternum */}
          <line x1="230" y1="158" x2="230" y2="260" stroke="rgba(219,38,29,0.5)" strokeWidth="1.5" strokeDasharray="5 3"/>
          {/* Ribs left */}
          {[
            [230,170,195,175,170,192],
            [230,185,193,192,165,208],
            [230,200,191,210,162,225],
            [230,215,190,228,160,242],
            [230,228,191,244,163,256],
          ].map(([x1,y1,cx1,cy1,x2,y2], i) => (
            <path key={`rl${i}`}
              d={`M${x1} ${y1} Q${cx1} ${cy1} ${x2} ${y2}`}
              stroke={`rgba(219,38,29,${0.42-i*0.04})`} strokeWidth="1.2" fill="none" strokeLinecap="round"/>
          ))}
          {/* Ribs right */}
          {[
            [230,170,265,175,290,192],
            [230,185,267,192,295,208],
            [230,200,269,210,298,225],
            [230,215,270,228,300,242],
            [230,228,269,244,297,256],
          ].map(([x1,y1,cx1,cy1,x2,y2], i) => (
            <path key={`rr${i}`}
              d={`M${x1} ${y1} Q${cx1} ${cy1} ${x2} ${y2}`}
              stroke={`rgba(219,38,29,${0.42-i*0.04})`} strokeWidth="1.2" fill="none" strokeLinecap="round"/>
          ))}

          {/* ══ SPINE ══ */}
          {[160,172,184,196,208,220,232,244,256,268,280,292,304].map((y, i) => (
            <ellipse key={i} cx="230" cy={y} rx="7" ry="5"
              fill="rgba(219,38,29,0.12)" stroke="rgba(219,38,29,0.32)" strokeWidth="0.8"/>
          ))}

          {/* ══ PELVIS ══ */}
          <path d="M175 355 C162 360 154 375 158 392 L230 400 L302 392 C306 375 298 360 285 355 Z"
            fill="rgba(80,10,10,0.6)" stroke="rgba(219,38,29,0.55)" strokeWidth="1.2"/>
          <ellipse cx="195" cy="375" rx="22" ry="18" fill="none" stroke="rgba(219,38,29,0.3)" strokeWidth="1"/>
          <ellipse cx="265" cy="375" rx="22" ry="18" fill="none" stroke="rgba(219,38,29,0.3)" strokeWidth="1"/>

          {/* ══ UPPER ARMS ══ */}
          {/* Left upper arm */}
          <path d="M140 162 C118 170 105 195 103 222 C101 245 108 260 118 268 C122 278 122 295 120 312"
            stroke="#db261d" strokeWidth="26" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M140 162 C118 170 105 195 103 222 C101 245 108 260 118 268 C122 278 122 295 120 312"
            stroke="url(#bodyGV)" strokeWidth="24" strokeLinecap="round" fill="none"/>
          {/* Right upper arm */}
          <path d="M320 162 C342 170 355 195 357 222 C359 245 352 260 342 268 C338 278 338 295 340 312"
            stroke="#db261d" strokeWidth="26" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M320 162 C342 170 355 195 357 222 C359 245 352 260 342 268 C338 278 338 295 340 312"
            stroke="url(#bodyGV)" strokeWidth="24" strokeLinecap="round" fill="none"/>

          {/* ══ ELBOW JOINTS ══ */}
          <ellipse cx="120" cy="316" rx="16" ry="13" fill="rgba(60,5,5,0.8)" stroke="#db261d" strokeWidth="1.3"/>
          <ellipse cx="340" cy="316" rx="16" ry="13" fill="rgba(60,5,5,0.8)" stroke="#db261d" strokeWidth="1.3"/>

          {/* ══ FOREARMS ══ */}
          {/* Left forearm */}
          <path d="M116 322 C110 345 108 368 108 390 L110 415"
            stroke="#db261d" strokeWidth="20" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M116 322 C110 345 108 368 108 390 L110 415"
            stroke="url(#bodyGV)" strokeWidth="18" strokeLinecap="round" fill="none"/>
          {/* Right forearm */}
          <path d="M344 322 C350 345 352 368 352 390 L350 415"
            stroke="#db261d" strokeWidth="20" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M344 322 C350 345 352 368 352 390 L350 415"
            stroke="url(#bodyGV)" strokeWidth="18" strokeLinecap="round" fill="none"/>

          {/* ══ WRISTS + HANDS ══ */}
          {/* Left */}
          <ellipse cx="110" cy="422" rx="13" ry="9" fill="url(#bodyGV)" stroke="#db261d" strokeWidth="1"/>
          <path d="M100 428 Q104 445 106 455 M107 428 Q108 448 109 460 M114 428 Q114 448 113 460 M120 428 Q119 447 118 456"
            stroke="#db261d" strokeWidth="5" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M100 428 Q104 445 106 455 M107 428 Q108 448 109 460 M114 428 Q114 448 113 460 M120 428 Q119 447 118 456"
            stroke="url(#bodyGV)" strokeWidth="4" strokeLinecap="round" fill="none"/>
          {/* Right */}
          <ellipse cx="350" cy="422" rx="13" ry="9" fill="url(#bodyGV)" stroke="#db261d" strokeWidth="1"/>
          <path d="M340 428 Q341 447 342 456 M346 428 Q346 448 347 460 M353 428 Q352 448 351 460 M360 428 Q356 445 354 455"
            stroke="#db261d" strokeWidth="5" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M340 428 Q341 447 342 456 M346 428 Q346 448 347 460 M353 428 Q352 448 351 460 M360 428 Q356 445 354 455"
            stroke="url(#bodyGV)" strokeWidth="4" strokeLinecap="round" fill="none"/>

          {/* ══ THIGHS ══ */}
          {/* Left thigh */}
          <path d="M188 400 L178 460 L172 510"
            stroke="#db261d" strokeWidth="32" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M188 400 L178 460 L172 510"
            stroke="url(#bodyGV)" strokeWidth="30" strokeLinecap="round" fill="none"/>
          {/* Right thigh */}
          <path d="M272 400 L282 460 L288 510"
            stroke="#db261d" strokeWidth="32" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M272 400 L282 460 L288 510"
            stroke="url(#bodyGV)" strokeWidth="30" strokeLinecap="round" fill="none"/>

          {/* ══ KNEE JOINTS ══ */}
          <ellipse cx="170" cy="516" rx="20" ry="16" fill="rgba(60,5,5,0.85)" stroke="#db261d" strokeWidth="1.5"/>
          <ellipse cx="290" cy="516" rx="20" ry="16" fill="rgba(60,5,5,0.85)" stroke="#db261d" strokeWidth="1.5"/>
          {/* Kneecap detail */}
          <ellipse cx="170" cy="514" rx="10" ry="8" fill="none" stroke="rgba(219,38,29,0.45)" strokeWidth="1"/>
          <ellipse cx="290" cy="514" rx="10" ry="8" fill="none" stroke="rgba(219,38,29,0.45)" strokeWidth="1"/>

          {/* ══ SHINS ══ */}
          {/* Left */}
          <path d="M168 528 L162 575 L160 600"
            stroke="#db261d" strokeWidth="22" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M168 528 L162 575 L160 600"
            stroke="url(#bodyGV)" strokeWidth="20" strokeLinecap="round" fill="none"/>
          {/* Right */}
          <path d="M292 528 L298 575 L300 600"
            stroke="#db261d" strokeWidth="22" strokeLinecap="round" fill="none" filter="url(#gB)"/>
          <path d="M292 528 L298 575 L300 600"
            stroke="url(#bodyGV)" strokeWidth="20" strokeLinecap="round" fill="none"/>

          {/* ══ FEET ══ */}
          <ellipse cx="158" cy="607" rx="24" ry="10" fill="url(#bodyGV)" stroke="#db261d" strokeWidth="1.2"/>
          <ellipse cx="302" cy="607" rx="24" ry="10" fill="url(#bodyGV)" stroke="#db261d" strokeWidth="1.2"/>

          {/* ══ SCAN LINE ══ */}
          <rect x="100" y={scanY} width="260" height="28" fill="url(#scanG)" clipPath="url(#bodyClip)"/>

          {/* ══ JOINT NODE DOTS ══ */}
          {[
            [230,138],[230,165],[230,200],[230,240],[230,280],[230,310],
            [155,155],[305,155],[170,516],[290,516],
            [120,316],[340,316],
          ].map(([cx,cy],i) => (
            <circle key={i} cx={cx} cy={cy} r="2.5"
              fill={`rgba(255,100,80,${0.5+Math.sin(i)*0.3})`}
              style={{ animation: `nodeFlicker ${1.6+i*0.22}s ease-in-out infinite ${i*0.15}s` }}
            />
          ))}

          {/* ══ PAIN POINTS (interactive) ══ */}
          {PAIN_POINTS.map((p) => {
            const isHov = hovered === p.id;
            return (
              <g key={p.id}
                style={{ cursor: 'pointer' }}
                onMouseEnter={() => setHovered(p.id)}
                onMouseLeave={() => setHovered(null)}
              >
                {/* Outer soft halo */}
                <circle cx={p.cx} cy={p.cy} r={isHov ? 30 : 20}
                  fill="url(#painG)" opacity={isHov ? 0.35 : 0.18}
                  style={{ transition: 'all 0.3s' }}/>
                {/* Mid ring */}
                <circle cx={p.cx} cy={p.cy} r={isHov ? 16 : 10}
                  fill="url(#painG)" opacity={isHov ? 0.65 : 0.45}
                  style={{ transition: 'all 0.3s' }}/>
                {/* Core dot */}
                <circle cx={p.cx} cy={p.cy} r={isHov ? 7 : 5}
                  fill={isHov ? '#fff' : '#ffaa44'}
                  filter="url(#gS)"
                  style={{ transition: 'all 0.3s' }}/>
                {/* Ripple 1 */}
                <circle cx={p.cx} cy={p.cy} fill="none"
                  stroke={isHov ? '#ffcc44' : '#ff4400'}
                  strokeWidth={isHov ? 1.5 : 1}
                  opacity="0.7">
                  <animate attributeName="r" values={`5;${isHov?28:22};5`}
                    dur={`${isHov?1.4:2.2}s`} repeatCount="indefinite"/>
                  <animate attributeName="opacity" values="0.9;0;0.9"
                    dur={`${isHov?1.4:2.2}s`} repeatCount="indefinite"/>
                </circle>
                {/* Ripple 2 offset */}
                <circle cx={p.cx} cy={p.cy} fill="none"
                  stroke="#ff6600" strokeWidth="1" opacity="0.5">
                  <animate attributeName="r" values={`5;${isHov?28:22};5`}
                    dur={`${isHov?1.4:2.2}s`} repeatCount="indefinite" begin="0.5s"/>
                  <animate attributeName="opacity" values="0.9;0;0.9"
                    dur={`${isHov?1.4:2.2}s`} repeatCount="indefinite" begin="0.5s"/>
                </circle>
              </g>
            );
          })}

          <style>{`
            @keyframes nodeFlicker {
              0%, 100% { opacity: 0.35; }
              50%       { opacity: 0.85; }
            }
          `}</style>
        </svg>
      </div>

      {/* ══ HOVER TOOLTIP ══ */}
      {hovered && (() => {
        const p = PAIN_POINTS.find(x => x.id === hovered);
        const leftSide = p.cx > 230;
        return (
          <div style={{
            position: 'absolute',
            top: `${(p.cy / 620) * 100}%`,
            [leftSide ? 'right' : 'left']: leftSide ? '10px' : '10px',
            transform: 'translateY(-50%)',
            background: 'rgba(10,0,0,0.92)',
            border: '1px solid rgba(219,38,29,0.7)',
            borderRadius: '10px',
            padding: '8px 14px',
            pointerEvents: 'none',
            backdropFilter: 'blur(10px)',
            boxShadow: '0 0 20px rgba(219,38,29,0.3)',
            zIndex: 10,
            whiteSpace: 'nowrap',
          }}>
            <div style={{ color: '#ffaa44', fontSize: '11px', fontWeight: 700 }}>● {p.label}</div>
            <div style={{ color: 'rgba(255,180,160,0.8)', fontSize: '10px', marginTop: '2px' }}>{p.desc}</div>
          </div>
        );
      })()}

      {/* ══ ALWAYS-VISIBLE LABELS ══ */}
      {PAIN_POINTS.map((p) => {
        const leftSide = p.cx > 230;
        return (
          <div key={p.id} style={{
            position: 'absolute',
            top: `${(p.cy / 620) * 100}%`,
            [leftSide ? 'right' : 'left']: leftSide ? '6px' : '6px',
            transform: 'translateY(-50%)',
            background: 'rgba(10,0,0,0.78)',
            border: `1px solid rgba(219,38,29,${hovered === p.id ? 0.9 : 0.45})`,
            borderRadius: '8px',
            padding: '4px 10px',
            pointerEvents: 'none',
            backdropFilter: 'blur(8px)',
            boxShadow: hovered === p.id ? '0 0 16px rgba(219,38,29,0.5)' : 'none',
            transition: 'all 0.3s',
            zIndex: 5,
            whiteSpace: 'nowrap',
            display: hovered === p.id ? 'none' : 'block',
          }}>
            <div style={{ color: hovered === p.id ? '#ffcc44' : '#ff8855', fontSize: '10px', fontWeight: 700 }}>
              ● {p.label}
            </div>
          </div>
        );
      })}
    </div>
  );
};

